import{b as i,a as e,_ as s}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as o,o as t,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Gestión de autenticación y dispositivos conectados","description":"","frontmatter":{},"headers":[],"relativePath":"es/Safety/authentication-and-login-devices.md","filePath":"es/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),c={name:"es/Safety/authentication-and-login-devices.md"};function r(l,a,p,u,h,m){return t(),n("div",null,[...a[0]||(a[0]=[d('<h1 id="gestion-de-autenticacion-y-dispositivos-conectados" tabindex="-1">Gestión de autenticación y dispositivos conectados <a class="header-anchor" href="#gestion-de-autenticacion-y-dispositivos-conectados" aria-label="Permalink to &quot;Gestión de autenticación y dispositivos conectados&quot;">​</a></h1><p>La gestión de autenticación permite revisar inicios de sesión, sesiones activas y dispositivos conectados al panel o a páginas de usuario.</p><h2 id="inicio-de-sesion-de-administrador" tabindex="-1">Inicio de sesión de administrador <a class="header-anchor" href="#inicio-de-sesion-de-administrador" aria-label="Permalink to &quot;Inicio de sesión de administrador&quot;">​</a></h2><p>El administrador entra desde la pantalla de login del panel para gestionar archivos y ajustes.</p><p><img src="'+i+'" alt="Login de administrador" loading="lazy"></p><p>La cuenta administradora tiene permisos altos. Mantén sus credenciales bien protegidas.</p><h2 id="inicio-de-sesion-de-usuario" tabindex="-1">Inicio de sesión de usuario <a class="header-anchor" href="#inicio-de-sesion-de-usuario" aria-label="Permalink to &quot;Inicio de sesión de usuario&quot;">​</a></h2><p>También existe una pantalla de inicio de sesión para usuarios.</p><p><img src="'+e+'" alt="Login de usuario" loading="lazy"></p><p>Si usas subida pública o acceso limitado, el login de usuario ayuda a saber quién realizó cada acción.</p><h2 id="pantalla-de-autenticacion" tabindex="-1">Pantalla de autenticación <a class="header-anchor" href="#pantalla-de-autenticacion" aria-label="Permalink to &quot;Pantalla de autenticación&quot;">​</a></h2><p>La pantalla de gestión muestra sesiones y dispositivos conectados.</p><p><img src="'+s+'" alt="Gestión de autenticación" loading="lazy"></p><h2 id="que-revisar-en-dispositivos" tabindex="-1">Qué revisar en dispositivos <a class="header-anchor" href="#que-revisar-en-dispositivos" aria-label="Permalink to &quot;Qué revisar en dispositivos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Descripción</th></tr></thead><tbody><tr><td>Dispositivo conectado</td><td>Dispositivos con sesión activa</td></tr><tr><td>IP / ubicación</td><td>Referencia del origen de acceso</td></tr><tr><td>Último acceso</td><td>Indica si el dispositivo sigue en uso</td></tr><tr><td>Revocar</td><td>Cierra sesiones antiguas o sospechosas</td></tr></tbody></table><h2 id="si-detectas-algo-sospechoso" tabindex="-1">Si detectas algo sospechoso <a class="header-anchor" href="#si-detectas-algo-sospechoso" aria-label="Permalink to &quot;Si detectas algo sospechoso&quot;">​</a></h2><ol><li>Revoca la sesión del dispositivo.</li><li>Cambia contraseña de administrador y tokens relacionados.</li><li>Revisa credenciales de Cloudflare, GitHub y canales de almacenamiento.</li><li>Regenera API Tokens si es necesario.</li></ol><h2 id="consejos-de-operacion" tabindex="-1">Consejos de operación <a class="header-anchor" href="#consejos-de-operacion" aria-label="Permalink to &quot;Consejos de operación&quot;">​</a></h2><ul><li>No dejes sesiones abiertas en equipos compartidos.</li><li>Mantén pocas cuentas con permisos de administrador.</li><li>Revisa periódicamente los dispositivos conectados.</li><li>Elimina sesiones antiguas o que ya no reconozcas.</li></ul>',19)])])}const _=o(c,[["render",r]]);export{b as __pageData,_ as default};
